"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["2940"],{76569(e,i,a){a.r(i),a.d(i,{default:()=>r});var t=a(74848),o=a(47643),n=JSON.parse('{"id":200,"it":{"title":"Titolo: Saggio sulla scuola secondaria di primo grado","prompt":"Please write a narrative essay of about 800 words. The essay should have an introduction, three distinct sections, and a conclusion. Each section should focus on a single event related to the main theme, which should be present throughout the essay. \\n\\n1. For the first section, focus on detailed descriptions of a specific skill or technique, including its artistic beauty and the joy of trying it for the first time.\\n2. In the second section, describe an innovative idea or concept, including details of its implementation and the deeper insights gained from the innovation.\\n3. The third section should revolve around a deeper aspect, such as cultural heritage, self-worth, or responsibility.\\n\\nBefore starting the essay, please share your interpretation of the title, including its surface and deeper meanings, and how they can be related to specific events or objects. Respond in Italian. Then, provide an outline of the essay, including the introduction, the main points and events for each of the three sections, and the conclusion.The title of the essay is [XXX], and the material is [xxxx].","description":"Ho bisogno che tu scriva un saggio nello stile di una narrazione, di circa 800 parole. Il saggio \xe8 diviso in un inizio, tre livelli e una conclusione. L\'inizio, la conclusione e ogni livello devono seguire il titolo, che deve essere presente in tutto il testo, e ogni livello deve essere una cosa separata. Il primo livello deve riguardare la descrizione specifica dell\'abilit\xe0 (descrizione dettagliata dell\'azione, bellezza artistica, gioia del primo tentativo, vicino al titolo); il secondo livello deve avere un contenuto un po\' innovativo (descrizione dettagliata dell\'azione, idee innovative, innovazione dopo l\'esperienza della verit\xe0 pi\xf9 profonda, vicino al titolo); il terzo livello deve riguardare il contenuto pi\xf9 profondo (eredit\xe0 culturale/autostima/responsabilit\xe0, vicino al titolo). Per quanto riguarda il titolo, ci sono un significato superficiale e un significato pi\xf9 profondo (significato derivato), che dovrebbero essere pienamente riflessi nel testo.\\nHo bisogno che mi diciate innanzitutto la vostra interpretazione del titolo, quali sono i due significati e a quali cose specifiche possono corrispondere. Poi mi dia uno schema che includa: un paragrafo di apertura specifico, una frase principale a tre livelli e un evento specifico, e un paragrafo di chiusura specifico.\\nIl titolo \xe8 \\"xxxx\\" e il materiale \xe8 [xxxx].","remark":"Dopo aver eseguito questo prompt, digitate \\"Converti questi in un saggio\\" per vedere se il saggio funziona meglio. Contributo di @Qizhen-Yang."},"tags":["contribute","pedagogy"],"website":null,"count":3243,"related":[{"id":182,"title":"Quadrupla induzione strutturale","remark":"Un riassunto a pi\xf9 livelli dell\'articolo viene sintetizzato e pu\xf2 essere utilizzato anche per spiegare parole e frasi e fare associazioni. Contributo di @ergf991. (C\'\xe8 una grande differenza tra la versione inglese e quella cinese di questo prompt, per favore cambiate lingua se dovete usare la versione inglese)."},{"id":265,"title":"Insegnante privato","remark":"Contributo di @EmmmmmmaWWWWW."},{"id":236,"title":"Assistente di memoria per l\'associazione di parole","remark":"Memorizzazione di parole basata su scenari. Contributo di @FIREnotfire."}],"metaTitle":"Saggista: Narrativa","metaDescription":"Saggio narrativo? Struttura in 3 parti. Focus su abilit\xe0, innovazione e valori profondi. Provalo ora.","faq":[{"q":"Un tema scolastico AI prende voti alti?","a":"La struttura segue i criteri di correzione (3 livelli, filo narrativo/tematico, riferimento al titolo) e pu\xf2 arrivare a voti medio-alti, ma il docente nota subito gli stilemi AI (troppa perfezione, mancanza di tracce personali) e pu\xf2 penalizzare. Usa come traccia e integra con esperienze personali."},{"q":"L\'interpretazione dell\'AI ha abbastanza profondit\xe0?","a":"Arriva a \xabtrasmissione culturale, auto-valore, senso di responsabilit\xe0\xbb ma cade nei luoghi comuni. Aggiungi \xabevita frasi fatte da tema, usa dettagli concreti\xbb: questo rompe il template."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,t.jsx)(o.A,{prompt:n,currentLanguage:"it"})}}}]);